struct PaymentDemoScreen: View {
    @State private var showingAlert = false
    @State private var alertMessage = ""
    @State private var isProcessing = false

    var body: some View {
        NavigationView {
            VStack(spacing: 24) {
                Text("Stripe Payment Demo")
                    .font(.title2)
                    .fontWeight(.semibold)

                VStack(alignment: .leading, spacing: 12) {
