                }
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding()
                .background(Color(.secondarySystemBackground))
                .cornerRadius(16)

                Button(action: simulatePayment) {
                    HStack {
                        if isProcessing {
                            ProgressView()
                                .progressViewStyle(CircularProgressViewStyle(tint: .white))
                        }
                        Text(isProcessing ? "Processing..." : "Pay with Stripe")
                            .fontWeight(.semibold)
                    }
                    .frame(maxWidth: .infinity)
                    .padding()
                    .background(Color.blue)
                    .foregroundColor(.white)
                    .cornerRadius(14)
                }
                .disabled(isProcessing)

                Spacer()
            }
            .padding()
            .navigationTitle("Payments")
            .alert("Payment Demo", isPresented: $showingAlert) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(alertMessage)
            }
        }
    }

    func simulatePayment() {
        isProcessing = true

        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            let paymentMethodParams = STPPaymentMethodCardParams()
            paymentMethodParams.number = "4242424242424242"
            paymentMethodParams.expMonth = 12
            paymentMethodParams.expYear = 34
            paymentMethodParams.cvc = "123"

            let billingDetails = STPPaymentMethodBillingDetails()
            billingDetails.name = "Investor Demo"

            let params = STPPaymentMethodParams(
                card: paymentMethodParams,
                billingDetails: billingDetails,
                metadata: ["demo": "true"]
            )

            STPAPIClient.shared.createPaymentMethod(with: params) { _, error in
                DispatchQueue.main.async {
                    isProcessing = false
                    if let error = error {
                        alertMessage = "Stripe initialized, but payment method creation failed: \(error.localizedDescription)"
                    } else {
                        alertMessage = "Demo payment method created successfully. Stripe integration is working for the presentation."
                    }
                    showingAlert = true
                }
            }
